use std::fmt;

struct Vector3 {
    x: f64,
    y: f64,
    z: f64,
}

impl std::ops::Add for Vector3 {
    type Output = Self;

    fn add(self, other: Self) -> Self::Output {
        Vector3 {
            x: self.x + other.x,
            y: self.y + other.y,
            z: self.z + other.z,
        }
    }
}

fn main() {
    let v1 = Vector3 { x: 1.0, y: 2.0, z: 3.0 };
    let v2 = Vector3 { x: 4.0, y: -1.0, z: 5.0 };

    let sum_vector = v1 + v2;

    println!("Vector Addition Result:");
    println!("X: {}", sum_vector.x);
    println!("Y: {}", sum_vector.y);
    println!("Z: {}", sum_vector.z);
}

use std::fmt::{self, Display};

struct Point {
    x: i32,
    y: i32,
}

impl Display for Point {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "({}, {} )", self.x, self.y)
    }
}

