    type Output;
    fn add(self, other: Self) -> Self::Output;
}

impl Addable for Point {
    type Output = Point;
    fn add(self, other: Self) -> Point {
        Point {
            x: self.x + other.x,
            y: self.y + other.y,
        }
    }
}

